import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  // Simplest cases
  it.todo("empty grid stays empty -- []");
  it.todo("single live cell dies from underpopulation -- []");

  // Rule-based examples
  it.todo("underpopulation: two adjacent live cells die -- []");
  it.todo("survival: live cell with 2 neighbors survives -- [(1,1)]");
  it.todo("survival: live cell with 3 neighbors survives -- [(1,1)]");
  it.todo("overpopulation: live cell with 4 neighbors dies -- []");
  it.todo("reproduction: dead cell with exactly 3 neighbors becomes alive -- [(1,1)]");

  // Pattern examples
  it.todo("blink oscillator: horizontal to vertical -- [(-1,1),(0,1),(1,1)]");
  it.todo("still life: 2x2 block remains unchanged -- [(0,0),(1,0),(0,1),(1,1)]");
});

