import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  // Simplest cases
  it("empty grid stays empty -- []", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("single live cell dies from underpopulation -- []", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });

  // Rule-based examples
  it("underpopulation: two adjacent live cells die -- []", () => {
    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
  });
  it("survival: live cell with 2 neighbors survives -- [(1,1)]", () => {
    expect(nextGeneration([[0, 0], [1, 1], [2, 2]])).toEqual([[1, 1]]);
  });
  it.todo("survival: live cell with 3 neighbors survives -- [(0,0),(1,0),(0,1),(1,1)]");
  it.todo("overpopulation: live cell with 4 neighbors dies -- [(0,0),(2,0),(0,1),(2,1)]");
  it.todo("reproduction: dead cell with exactly 3 neighbors becomes alive -- [(0,0),(1,0),(0,1),(1,1)]");

  // Pattern examples
  it.todo("blink oscillator: horizontal to vertical -- [(-1,1),(0,1),(1,1)]");
  it.todo("still life: 2x2 block remains unchanged -- [(0,0),(1,0),(0,1),(1,1)]");
});

